  send_mouse(*canvas, QEvent::MouseMove, origin + QPoint(25, -25), Qt::NoButton, Qt::RightButton, Qt::AltModifier);
  send_mouse(*canvas, QEvent::MouseButtonRelease, origin + QPoint(25, -25), Qt::RightButton, Qt::NoButton,
             Qt::AltModifier);
